After carefully analyzing the obfuscated code, I can see it's a **force-directed graph simulation** with particles, spring forces, repulsion, gravity centering, camera smoothing, and decorative stream particles.

Here's my clean implementation:

```javascript
const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SQRT_HALF = 0.707;

const simulationConfig = {
  attractionStrength: 4000,
  springStiffnessDefault: 0.004,
  velocityDamping: 0.92,
  centerGravity: 0.0003,
  maxStreamParticles: 40,
  streamDecay: 0.04,
  cameraSmoothing: 0.06,
};

const nodes = [
  { id: "hub",      label: "Hub",      r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",    label: "Alpha",    r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",     label: "Beta",     r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",    label: "Gamma",    r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",    label: "Delta",    r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon",  label: "Epsilon",  r: 12, x: 350, y: 150, vx: 0, vy: 0 },
];

const edges = [
  { source: "hub", target: "alpha",   restLength: 160, stiffness: 0.006 },
  { source: "hub", target: "beta",    restLength: 160, stiffness: 0.005 },
  { source: "hub", target: "gamma",   restLength: 170, stiffness: 0.004 },
  { source: "hub", target: "delta",   restLength: 170, stiffness: 0.004 },
  { source: "hub", target: "epsilon", restLength: 180, stiffness: 0.003 },
  { source: "alpha", target: "beta",  restLength: 200, stiffness: 0.002 },
  { source: "gamma", target: "delta", restLength: 220, stiffness: 0.002 },
  { source: "alpha", target: "epsilon", restLength: 200, stiffness: 0.002 },
];

const currentCamera = { x: 400, y: 300, zoom: 1 };
const targetCamera  = { x: 400, y: 300, zoom: 1 };

let streamParticles = [];
let tickCount = 0;

function findNodeById(nodeId) {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === nodeId) return nodes[i];
  }
  return null;
}

function applyForces() {
  // Repulsion between all node pairs
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      let dx = nodes[i].x - nodes[j].x;
      let dy = nodes[i].y - nodes[j].y;
      let distance = Math.sqrt(dx * dx + dy * dy) || 1;
      let repulsionForce = simulationConfig.attractionStrength / (distance * distance);
      let forceX = (dx / distance) * repulsionForce;
      let forceY = (dy / distance) * repulsionForce;
      nodes[i].vx += forceX;
      nodes[i].vy += forceY;
      nodes[j].vx -= forceX;
      nodes[j].vy -= forceY;
    }
  }

  // Spring forces along edges
  for (let i = 0; i < edges.length; i++) {
    let sourceNode = findNodeById(edges[i].source);
    let targetNode = findNodeById(edges[i].target);
    if (!sourceNode || !targetNode) continue;

    let dx = targetNode.x - sourceNode.x;
    let dy = targetNode.y - sourceNode.y;
    let distance = Math.sqrt(dx * dx + dy * dy) || 1;
    let displacement = distance - edges[i].restLength;
    let springForce = (edges[i].stiffness || simulationConfig.springStiffnessDefault) * displacement;

    sourceNode.vx += (dx / distance) * springForce;
    sourceNode.vy += (dy / distance) * springForce;
    targetNode.vx -= (dx / distance) * springForce;
    targetNode.vy -= (dy / distance) * springForce;
  }

  // Center gravity, damping, and position integration
  for (let i = 0; i < nodes.length; i++) {
    nodes[i].vx += (400 - nodes[i].x) * simulationConfig.centerGravity;
    nodes[i].vy += (300 - nodes[i].y) * simulationConfig.centerGravity;
    nodes[i].vx *= simulationConfig.velocityDamping;
    nodes[i].vy *= simulationConfig.velocityDamping;
    nodes[i].x += nodes[i].vx;
    nodes[i].y += nodes[i].vy;
  }
}

function spawnStreamParticle() {
  if (streamParticles.length >= simulationConfig.maxStreamParticles) return;

  let originNode = nodes[Math.floor(Math.random() * nodes.length)];
  let angle = Math.random() * TWO_PI;
  let speed = 0.3 + Math.random() * SQRT_HALF;

  streamParticles.push({
    x: originNode.x,
    y: originNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_HALF,
  });
}

function updateStreamParticles() {
  for (let i = streamParticles.length - 1; i >= 0; i--) {
    let particle = streamParticles[i];
    particle.vx *= 1 - simulationConfig.streamDecay * 0.125;
    particle.vy *= 1 - simulationConfig.streamDecay * 0.125;
    particle.x += particle.vx;
    particle.y += particle.vy;
    particle.age++;
    if (particle.age > particle.maxAge) {
      streamParticles.splice(i, 1);
    }
  }
}

function updateCamera() {
  currentCamera.x += (targetCamera.x - currentCamera.x) * simulationConfig.cameraSmoothing;
  currentCamera.y += (targetCamera.y - currentCamera.y) * simulationConfig.cameraSmoothing;
  currentCamera.zoom += (targetCamera.zoom - currentCamera.zoom) * simulationConfig.cameraSmoothing;
}

function simulationStep() {
  applyForces();
  updateStreamParticles();
  updateCamera();
  if (tickCount % 3 === 0) spawnStreamParticle();
  tickCount++;
}

setInterval(simulationStep, 16);
